/**
 * Data model for `<ve-chat-input>`.
 *
 * The composer value is a linear list of **segments** plus an independent list
 * of **attachments**:
 *
 * - A {@link ChatInputTextSegment} is a run of plain text.
 * - A {@link ChatInputNodeSegment} is an inline "island" (tag, select,
 *   editable variable, or any custom node) rendered by a registered
 *   {@link ChatInputNodeRender}. See `./node-renders`.
 *
 * Because most usage is plain text, the public `value` accepts either a raw
 * `string` (treated as a single text segment) or the structured
 * {@link ChatInputValue} object. Use {@link normalizeChatInputValue} to coerce
 * any input into the structured form.
 */
/** A run of plain text inside the composer. */
export interface ChatInputTextSegment {
    type: 'text';
    /** The text content. */
    text: string;
}
/**
 * An inline node ("island") inside the composer, rendered by the render
 * registered for {@link ChatInputNodeSegment.nodeType}.
 */
export interface ChatInputNodeSegment {
    type: 'node';
    /** Stable id used as the DOM key for this node instance. */
    id: string;
    /** Registered render key, e.g. `'tag' | 'select' | 'variable'`. */
    nodeType: string;
    /** Arbitrary data passed to the render (label, value, options, …). */
    data?: Record<string, unknown>;
}
/** A single segment of the composer value. */
export type ChatInputSegment = ChatInputTextSegment | ChatInputNodeSegment;
/** Upload / attachment status. */
export type ChatInputAttachmentStatus = 'init' | 'uploading' | 'done' | 'error';
/** An attachment shown in the composer header (image, document, …). */
export interface ChatInputAttachment {
    /** Stable id used as the DOM key. */
    id: string;
    /** Alternative stable id (compatible with UploadItem). */
    uid?: string;
    /** Display name. */
    name: string;
    /**
     * Coarse file kind used to pick an icon, e.g. `'image' | 'file' | 'video'`.
     * Free-form; consumers may use their own values.
     */
    kind?: string;
    /** File size in bytes. */
    size?: number;
    /** MIME type of the file. */
    type?: string;
    /** Resolved URL of the uploaded file. */
    url?: string;
    /** Thumbnail URL for image previews. */
    thumbUrl?: string;
    /** Upload status. Defaults to `'done'`. */
    status?: ChatInputAttachmentStatus;
    /** Upload progress percentage (0–100) when `status === 'uploading'`. */
    percent?: number;
    /** Response data from upload request. */
    response?: unknown;
    /** Original File object. */
    originFile?: File;
    /** Children files (for directory upload). */
    children?: string;
    /** Arbitrary metadata carried through unchanged. */
    meta?: Record<string, unknown>;
}
/** The structured composer value: ordered segments + independent attachments. */
export interface ChatInputValue {
    segments: ChatInputSegment[];
    attachments: ChatInputAttachment[];
}
/** Accepted `value` shapes: a plain string or the structured object. */
export type ChatInputValueInput = string | ChatInputValue;
/** A command trigger that opens a panel when its prefix is typed. */
export interface ChatInputTrigger {
    /** Character(s) that activate the trigger, e.g. `'/'` or `'@'`. */
    prefix: string;
}
/** Detail for the `ve-chat-input-trigger` event. */
export interface ChatInputTriggerDetail {
    /** The matched trigger, or `null` when no trigger is active. */
    trigger: ChatInputTrigger | null;
    /** The query typed after the prefix (excludes the prefix itself). */
    query: string;
}
/** Type guard for the structured value object. */
export declare function isChatInputValue(value: ChatInputValueInput | null | undefined): value is ChatInputValue;
/** Coerce any accepted value shape into the structured {@link ChatInputValue}. */
export declare function normalizeChatInputValue(value: ChatInputValueInput | null | undefined): ChatInputValue;
/** Default plain-text projection of a node segment when no render override. */
export declare function defaultNodeText(node: ChatInputNodeSegment): string;
/**
 * Plain-text projection of a structured value, used for emptiness checks and
 * for consumers that only care about the text the user typed.
 *
 * @param getNodeText Optional override resolving a node's text (e.g. from a
 *   render registry). Falls back to {@link defaultNodeText}.
 */
export declare function chatInputValueToText(value: ChatInputValue, getNodeText?: (node: ChatInputNodeSegment) => string): string;
/** Whether a structured value carries no segments and no attachments. */
export declare function isChatInputValueEmpty(value: ChatInputValue): boolean;
/**
 * Where a {@link ChatInputTriggerPanel} is anchored:
 *
 * - `'top'` floats the panel above the whole composer (the classic command
 *   palette look).
 * - `'caret'` anchors the panel just below the caret (right after the typed
 *   prefix), following the text as the user types.
 */
export type ChatInputTriggerPanelPlacement = 'top' | 'caret';
/**
 * A trigger-bound floating panel owned by `<ve-chat-input>`. The component
 * shows / hides and positions the panel automatically when the bound trigger
 * becomes active; the panel **body is supplied by the consumer** via the
 * `panel-<key>` slot, so the component stays content- and interaction-agnostic.
 */
export interface ChatInputTriggerPanel {
    /**
     * Unique key. Also the slot suffix used to project the panel body: put your
     * content in the `panel-<key>` slot.
     */
    key: string;
    /** Trigger prefix that opens this panel, e.g. `'/'` — matches a `triggers[].prefix`. */
    trigger: string;
    /** Anchor mode. Defaults to `'top'`. */
    placement?: ChatInputTriggerPanelPlacement;
}
